import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { Link, useNavigate } from 'react-router-dom';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    
    const audioRef = useRef(null);
    const user = JSON.parse(localStorage.getItem('user')); // Lấy user từ local
    const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

    // 1. Tải danh sách nhạc
    const fetchSongs = async () => {
        try {
            const res = await axios.get('http://localhost:5000/api/songs');
            setSongs(res.data);
        } catch (err) {
            console.error("Lỗi khi tải danh sách nhạc", err);
        }
    };

    useEffect(() => {
        fetchSongs();
    }, []);

    // 2. Logic điều khiển nhạc
    const playSong = (index) => {
        setCurrentIndex(index);
        setIsPlaying(true);
    };

    const togglePlay = () => {
        if (isPlaying) audioRef.current.pause();
        else audioRef.current.play();
        setIsPlaying(!isPlaying);
    };

    const nextSong = () => {
        const nextIndex = (currentIndex + 1) % songs.length;
        setCurrentIndex(nextIndex);
        setIsPlaying(true);
    };

    const formatTime = (time) => {
        if (isNaN(time)) return "0:00";
        const min = Math.floor(time / 60);
        const sec = Math.floor(time % 60);
        return `${min}:${sec < 10 ? '0' : ''}${sec}`;
    };

    // 3. Logic xóa bài hát
    const handleDelete = async (e, id) => {
        e.stopPropagation(); // Ngăn sự kiện nhấn vào card để phát nhạc
        if (window.confirm("Bạn có chắc chắn muốn xóa bài hát này?")) {
            try {
                await axios.delete(`http://localhost:5000/api/songs/${id}`);
                alert("Đã xóa bài hát!");
                fetchSongs();
            } catch (err) {
                alert("Lỗi: " + (err.response?.data?.message || err.message));
            }
        }
    };

    return (
        <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '120px' }}>
            <h2 style={{ borderBottom: '2px solid #1db954', paddingBottom: '10px', color: '#1db954' }}>
                Khám phá âm nhạc
            </h2>

            {/* GRID DANH SÁCH BÀI HÁT */}
            <div style={{ 
                display: 'grid', 
                gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', 
                gap: '25px', 
                marginTop: '20px' 
            }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={cardStyle} onClick={() => playSong(index)}>
                        <div style={{ position: 'relative' }}>
                            <img 
                                src={`http://localhost:5000${song.imageUrl}`} 
                                alt={song.title} 
                                style={{ width: '100%', height: '200px', objectFit: 'cover', borderRadius: '10px' }} 
                            />
                            {currentIndex === index && isPlaying && (
                                <div style={playingOverlay}>🎶 Đang phát</div>
                            )}
                        </div>

                        <h4 style={{ margin: '15px 0 5px 0', fontSize: '18px' }}>{song.title}</h4>
                        
                        {/* Link đến trang cá nhân của nghệ sĩ/người đăng */}
                        <Link 
                            to={`/profile/${song.userId}`} 
                            style={{ color: '#666', fontSize: '14px', textDecoration: 'none' }}
                            onClick={(e) => e.stopPropagation()} // Không phát nhạc khi bấm vào tên
                        >
                            👤 {song.artist}
                        </Link>
                        
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '15px' }}>
                            <button style={playBtnStyle}>▶ PLAY</button>
                            
                            {/* Chỉ hiện nút xóa nếu là admin hoặc chính người đăng */}
                            {(user?.role === 'admin' || user?._id === song.userId) && (
                                <button onClick={(e) => handleDelete(e, song._id)} style={deleteBtnStyle}>
                                    🗑️ Xóa
                                </button>
                            )}
                        </div>
                    </div>
                ))}
            </div>

            {/* TRÌNH PHÁT NHẠC CỐ ĐỊNH (BOTTOM PLAYER) */}
            {currentSong && (
                <div style={playerBarContainer}>
                    <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={miniImgStyle} alt="thumb" />
                        <div>
                            <div style={{ fontWeight: 'bold' }}>{currentSong.title}</div>
                            <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
                        </div>
                    </div>

                    <div style={{ width: '40%', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                        <div style={{ display: 'flex', gap: '20px', marginBottom: '5px' }}>
                            <button onClick={togglePlay} style={mainPlayBtn}>
                                {isPlaying ? '⏸' : '▶'}
                            </button>
                        </div>
                        <div style={{ display: 'flex', width: '100%', alignItems: 'center', gap: '10px' }}>
                            <span style={{ fontSize: '12px' }}>{formatTime(currentTime)}</span>
                            <input 
                                type="range" 
                                min="0" 
                                max={duration || 0} 
                                value={currentTime} 
                                onChange={(e) => { audioRef.current.currentTime = e.target.value; }}
                                style={{ flex: 1, accentColor: '#1db954', cursor: 'pointer' }}
                            />
                            <span style={{ fontSize: '12px' }}>{formatTime(duration)}</span>
                        </div>
                    </div>

                    <div style={{ width: '30%' }}></div>

                    <audio 
                        ref={audioRef}
                        src={`http://localhost:5000${currentSong.songUrl}`} 
                        autoPlay 
                        onTimeUpdate={() => setCurrentTime(audioRef.current.currentTime)}
                        onLoadedMetadata={() => setDuration(audioRef.current.duration)}
                        onEnded={nextSong}
                        onPlay={() => setIsPlaying(true)}
                        onPause={() => setIsPlaying(false)}
                    />
                </div>
            )}
        </div>
    );
};

// --- STYLES ---
const cardStyle = {
    background: '#fff',
    padding: '15px',
    borderRadius: '15px',
    boxShadow: '0 4px 15px rgba(0,0,0,0.08)',
    cursor: 'pointer',
    transition: 'transform 0.3s ease',
    border: '1px solid #eee'
};

const playingOverlay = {
    position: 'absolute', top: '10px', right: '10px', background: 'rgba(29, 185, 84, 0.9)',
    color: 'white', padding: '5px 10px', borderRadius: '20px', fontSize: '12px', fontWeight: 'bold'
};

const playBtnStyle = {
    background: '#1db954', color: 'white', border: 'none', padding: '8px 18px',
    borderRadius: '25px', cursor: 'pointer', fontWeight: 'bold'
};

const deleteBtnStyle = {
    background: '#fff', color: '#ff4d4d', border: '1px solid #ff4d4d',
    padding: '5px 10px', borderRadius: '8px', cursor: 'pointer', fontSize: '12px'
};

const playerBarContainer = {
    position: 'fixed', bottom: 0, left: 0, right: 0, background: '#181818',
    color: '#fff', padding: '15px 40px', display: 'flex', alignItems: 'center',
    boxShadow: '0 -5px 20px rgba(0,0,0,0.3)', zIndex: 1000
};

const miniImgStyle = { width: '55px', height: '55px', borderRadius: '5px', marginRight: '15px', objectFit: 'cover' };

const mainPlayBtn = {
    width: '45px', height: '45px', borderRadius: '50%', border: 'none',
    background: '#fff', color: '#000', fontSize: '20px', cursor: 'pointer'
};

export default Home;
